// ── Печатка ТОВ «ЕЙМ СКІЛ» (data URL, з прозорим фоном) ──
// Накладається опційно (options.withStamp) поверх блоку підпису.
export const STAMP_BASE64 = 'data:image/png;base64,'

// Накладка печатки поверх блоку підпису. Повертає порожній вузол, якщо withStamp вимкнено.
// relativePosition не займає місця у верстці — печатка «лягає» поверх лінії підпису.
export function stampOverlay(options, pos = {}) {
  if (!options?.withStamp) return { text: '' }
  const { x = 20, y = -44, w = 112 } = pos
  return { image: STAMP_BASE64, width: w, opacity: 0.82, relativePosition: { x, y } }
}
